    [src="https://www.gstatic.com/youtube/img/creator/yt_studio_logo_white.svg"] {
      @svg: escape(
        '<svg viewBox="0 0 97.55 24" xmlns="http://www.w3.org/2000/svg"><path fill="@{accent}" d="M17.1 0S6.4 0 3.8.7a4.15 4.15 0 0 0-3 3C0 6.4 0 12 0 12a45 45 0 0 0 .7 8.2 4.32 4.32 0 0 0 3 3c2.7.8 13.4.8 13.4.8s10.7 0 13.4-.7a4.32 4.32 0 0 0 3-3 45 45 0 0 0 .7-8.2s.1-5.7-.6-8.3a4.32 4.32 0 0 0-3-3C27.9 0 17.1 0 17.1 0m-3.4 6.9 8.9 5.1-8.9 5.1z"/><path fill="@{text}" d="M76.3.9v4.4c0 1.1 0 2 .1 3.3h-.1A3.36 3.36 0 0 0 73.4 7c-2.3 0-3.3 2-3.3 6.6V16c0 4.9.8 6.6 3.2 6.6a3.42 3.42 0 0 0 3.2-2.4h.1l.4 2.1h2.6V.9zm6.688.4c-1.126.032-1.687.55-1.687 2.1 0 1.7.599 2.1 1.799 2.1s1.8-.5 1.8-2.1-.6-2.1-1.8-2.1zM45 1.4c-3.6 0-5 1.7-5 4.9s1.1 4.5 3.7 6.8c1.6 1.4 2.8 2.5 2.8 4.8 0 1.5-.4 2.2-1.6 2.2s-1.7-.8-1.6-3.6h-3.1c-.6 4.2.8 6.1 4.5 6.2 3.5 0 5-1.5 5-5.4 0-3.1-1.3-4.4-3.7-6.6-1.9-1.8-2.8-2.5-2.8-4.6 0-1.4.3-2.2 1.6-2.2s1.6 1.1 1.5 3.9l3.1-.2c.5-4.2-.8-6.2-4.4-6.2m7.6 1.4-.4 4.5h-1.4v2.6H52v8.8c0 2.7.4 3.8 2.6 3.8a7.4 7.4 0 0 0 3.1-.6l-.6-2.2a5.2 5.2 0 0 1-1.3.2c-.5 0-.7-.3-.7-1.7V9.9h2.2V7.3H55V2.8zM91 7c-3.3 0-4.7 1.8-4.7 6.7v2.2c0 4.7 1.1 6.7 4.6 6.7s4.7-2 4.7-6.7v-2.2C95.6 8.9 94.3 7 91 7m-31.8.3v11.4c0 2.7.9 4 2.9 4a3.46 3.46 0 0 0 3.2-2.1h.1l.3 1.8h2.7V7.3H65v12a1.51 1.51 0 0 1-1.4 1c-.7 0-1-.6-1-1.9V7.3zm22.3 0v15.1h3.2V7.3zm9.4 2c1 0 1.3 1 1.3 3.1v4.7c0 2.2-.4 3.1-1.3 3.1s-1.2-.9-1.2-3.1v-4.7c0-2 .2-3.1 1.2-3.1M75 9.4a1.56 1.56 0 0 1 1.3.8v8.5c-.2.9-.9 1.4-1.4 1.3-1 0-1.3-1-1.3-4.4v-1.9c0-3.3.3-4.3 1.4-4.3"/></svg>'
      );
      content: url("data:image/svg+xml,@{svg}");
    }

    &,
    html,
    html[dark],
    html[dark][dark],
    &[dark],
    &[light],
    [light],
    html[light],
    html[light][light] {
      --yt-spec-black-pure-alpha-80: (null);
      --yt-spec-black-pure-alpha-60: (null);
      --yt-spec-black-1-alpha-98: (null);
      --yt-spec-black-1-alpha-95: (null);
      --iron-icon-fill-color: unset;

      --yt-spec-text-primary: @text;
      --ytcp-text-primary: @text;
      --ytcp-text-primary-inverse: @base;
      --ytcp-static-overlay-text-primary-inverse: @base;
      --ytcp-wordmark-text: @text;
      --ytcp-text-secondary: @subtext0;
      --ytcp-text-disabled: @subtext1;
      --ytcp-overlay-text-primary: @overlay2;

      --ytcp-general-background-a: @base;
      --yt-spec-base-background: @base;
      --yt-spec-black-3: @base;

      --yt-spec-brand-background-solid: @mantle;
      --ytcp-brand-background-solid: @mantle;
      --yt-spec-raised-background: @mantle;
      --ytcp-general-background-b: @mantle;
      --ytcp-analytics-reach-background: @mantle;
      --yt-spec-black-2: @mantle;

      --ytcp-general-background-c: @crust;
      --ytcp-menu-background: @surface0;

      --ytcp-container-border-color: @surface0;
      --ytcp-container-hovered-border-color: @surface0;
      --ytcp-line-divider-solid: @surface0;
      --ytcp-container-border-color-inverse: @subtext0;
      --ytcp-line-divider-solid-inverse: @subtext0;

      --ytcp-call-to-action: @accent;
      --ytcp-call-to-action-inverse: @mantle;
      --ytcp-call-to-action-raised-background: @accent;
      --yt-spec-brand-button-background: @accent;
      --ytcp-call-to-action-raised-disabled: @surface2;
      --ytcp-call-to-action-raised-disabled-background: @overlay2;
      --ytcp-call-to-action-raised-background-inverse: @base;
      --ytcp-call-to-action-raised-disabled-inverse: @surface2;
      --ytcp-call-to-action-raised-disabled-background-inverse: @overlay2;

      --yt-spec-brand-background-primary: @surface0;

      --yt-compact-link-icon-color: @overlay2;
      --ytcp-icon-active: @accent;
      --ytcp-icon-inactive: @overlay2;
      --ytcp-icon-disabled: @overlay0;
      --ytcp-icon-active-inverse: @overlay1;
      --ytcp-icon-disabled-inverse: @subtext1;

      --ytcp-error-red: @red;
      --ytcp-badge-red: @red;
      --ytcp-error-red-inverse: @red;
      --ytcp-themed-red-inverse: @red;
      --ytcp-themed-red: @accent;
      --ytcp-themed-blue: @accent;
      --ytcp-badge-blue: fade(@accent, 30%);
      --ytcp-badge-blue-solid: @blue;
      --ytcp-themed-blue-inverse: @blue;
      --ytcp-themed-green: @green;
      --ytmus-genre-primary-melon: @green;
      --ytcp-themed-green-inverse: @green;
      --ytcp-analytics-pine: @green;
      --ytcp-analytics-pine-inverse: @green;
      --ytcp-analytics-parrot: @green;
      --ytcp-themed-yellow: @peach;
      --ytmus-genre-primary-gold: @peach;
      --ytcp-yellow-inverse: @peach;
      --ytcp-badge-yellow: @peach;
      --ytcp-analytics-yellow: @peach;
      --ytcp-analytics-apricot: @peach;
      --ytcp-suggested-action: @teal;
      --ytcp-analytics-overview: @teal;
      --ytcp-analytics-revenue: @teal;
      --ytcp-analytics-default-secondary: @teal;
      --ytcp-analytics-royal-blue: @lavender;
      --ytcp-analytics-reach: @lavender;
      --ytcp-analytics-audience: @lavender;
      --ytcp-analytics-engagement: @pink;
      --ytcp-analytics-revenue-secondary: @pink;
      --ytcp-analytics-bubblegum: @flamingo;
      --ytmus-genre-primary-ruby: @flamingo;
      --ytmus-genre-primary-salmon: @mauve;
      --ytmus-genre-primary-orange: @maroon;
      --ytmus-genre-primary-sky: @sky;
      --ytmus-genre-primary-sky-inverse: @sky;

      --yt-spec-badge-chip-background: @surface1;
      --ytcp-focus-inverse: @accent;
      --ytcp-focus: @accent;
      --ytcp-selected-item: @accent;
      --ytcp-hover-item: @overlay2;
      --ytcp-chip-active-focus: @accent;
      --ytcp-playhead: @overlay2;
      --ytcp-playhead-inverse: @overlay2;
    }

    ytcp-button.destructive.ytls-error-dialog {
      color: @base;
    }

    yt-formatted-string.ytls-error-dialog,
    tp-yt-iron-icon.ytls-error-dialog {
      color: @text;
    }
  }
}

@-moz-document domain("m.youtube.com") {
  html[darker-dark-theme] {
    #catppuccin(@darkFlavor);
  }
  html {
    #catppuccin(@lightFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();

    background-color: @base !important;
    color: @text !important;

    /* Ambient mode */
    #cinematics {
      mix-blend-mode: lighten;
    }

    .mobile-topbar-header[data-mode="watch"],
    ytm-mobile-topbar-renderer:not([ambient-topbar]) {
      background: @base;
    }

    .mobile-topbar-header[data-mode="watch"] .mobile-topbar-logo,
    .mobile-topbar-header[data-mode="watch"] .mobile-topbar-title,
    .mobile-topbar-header[data-mode="watch"] .mobile-topbar-header-content {
      color: @text;
    }

    .yt-spec-bottom-sheet-layout__bottom-sheet-renderer-container,
    .modern-styling {
      background: @surface0;
    }

    .yt-spec-bottom-sheet-layout__bottom-sheet-layout-header-wrapper {
      border-bottom-color: @surface0;
    }

    .yt-spec-bottom-sheet-layout__bottom-sheet-content {
      color: @text;
    }

    /* Comment box */
    .engagement-panel-container {
      background: @mantle;
    }

    /* Bottom bar */
    ytm-pivot-bar-renderer {
      background: @mantle;
      color: @text;
      border-top-color: @surface0;
    }

    /* Chips */
    .chip-bar {
      background-color: @base;
    }

    [chip-style*="STYLE_"] {
      .chip-container {
        color: @text;
        background-color: @surface0;
      }

      &.selected .chip-container {
        color: @crust;
        background-color: @accent;
      }
    }

    /* Buttons */

    .yt-spec-touch-feedback-shape--touch-response {
      .yt-spec-touch-feedback-shape__fill {
        background-color: @text;
      }

      .yt-spec-touch-feedback-shape__stroke {
        border-color: @surface1;
      }
    }

    .yt-spec-touch-feedback-shape--overlay-touch-response-inverse
      .yt-spec-touch-feedback-shape__fill {
      background-color: @accent;
    }
    .yt-spec-touch-feedback-shape--overlay-touch-response
      .yt-spec-touch-feedback-shape__fill {
      background-color: @text;
    }
  }
}

/* ==UserStyle==
@name Last.fm Catppuccin
@namespace github.com/catppuccin/userstyles/styles/lastfm
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/lastfm
@version 2026.01.03
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/lastfm/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Alastfm
@description Soothing pastel theme for Last.fm
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("last.fm") {
  @media (prefers-color-scheme: light) {
    #catppuccin(@lightFlavor);
  }
  @media (prefers-color-scheme: dark) {
    #catppuccin(@darkFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    html, html body {
      color: @text;
      background-color: @base;
    }

    /* Components */

    a, .mimic-link {
      color: @accent;
    }

    .btn-primary() {
      background-color: @accent;
      color: @crust;

      &:hover {
        background-color: darken(@accent, 5%) !important;
        color: @crust !important;
      }
    }
    .btn-primary {
      .btn-primary();
    }
    .btn-secondary {
      background-color: @surface0;
      color: @text;

      &:hover {
        background-color: @surface1 !important;
        color: @text !important;
      }
    }
    .btn-cancel {
      color: @subtext1;
    }

    .dropdown-menu-clickable {
      background: @mantle;
      &::before {
        filter: @mantle-filter;
      }

      .dropdown-menu-clickable-item {
        color: @text;

        &:hover {
          background-color: @base !important;
        }

        &.dropdown-menu-clickable-item--selected {
          color: @accent;
        }
      }
    }
    .dropdown-menu-clickable-button {
      color: @subtext0;

      &:hover, &.disclose-active {
        color: @subtext1;
      }

      .section-with-settings &.section-control::before {
        border-right-color: @surface2;
      }

      &::after {
        filter: @subtext1-filter;
      }
    }

    .content-form {
      textarea, input, select {
        background-color: @mantle !important;
        color: @text !important;
        border-color: @surface1 !important;

        &:focus {
          box-shadow: 0 3px 9px 0 @surface0 !important;
        }
      }

      .lfm-form-radio input[type="radio"] {
        + label::before {
          background-color: @base;
          border-color: @overlay1;
        }
        &:checked + label::before {
          box-shadow: inset 0 0 0 4px @accent;
          border-color: @accent;
        }
      }

      .form-row-help-text, .footnotes {
        color: @subtext0;
      }

      legend {
        color: @subtext1;
      }
    }

    .search-form {
      .search-submit::before {
        filter: @overlay0-filter;
      }

      &::after {
        border-right-color: @surface1;
      }
    }

    // Alerts
    .alert-warning {
      background-color: fade(@peach, 30%);
      color: @peach;

      &::before {
        filter: @peach-filter;
      }
    }

    // Modals
    .modal-body {
      background: @mantle;
    }

    // Other

    .section-with-separator::after {
      background-color: @surface0;
    }

    .container {
      background: @base;
    }

    .content-top-back-link {
      color: @subtext0;

      a::before {
        filter: @overlay2-filter;
      }
    }

    /* Footer */
    .footer {
      background: @mantle;
      color: @text;

      .footer-heading {
        color: @subtext0;
      }

      .footer-language {
        color: @subtext0;
        &.footer-language--active {
          color: @text;
        }
      }

      .footer-timezone {
        color: @subtext0;
        strong {
          color: @text;
        }
      }

      .footer-legal {
        color: @subtext1;
      }

      .container {
        background: none;
      }
    }

    /* Header */
    .top-bar {
      background: @mantle;

      svg {
        filter: @accent-filter;
      }
    }
    .masthead {
      .masthead-search-toggle {
        &::before {
          filter: @text-filter;
        }
        &::after {
          background-color: @text;
        }
      }
      .masthead-nav .masthead-nav-control {
        color: @text;

        &::after {
          background-color: @text;
        }
      }

      .auth-avatar-notification-count-badge {
        background: @accent;
      }
      .auth-dropdown-menu {
        background: @mantle !important;

        .auth-dropdown-profile {
          background-color: @crust;

          .auth-dropdown-profile-info {
            .username {
              color: @text;
            }
            .scrobble-count {
              color: @subtext0;
            }
          }
        }
        .auth-dropdown-menu-links {
          background: @mantle;

          .auth-dropdown-menu-item .auth-dropdown-menu-link img {
            filter: @text-filter;
          }
        }
        .auth-dropdown-menu-footer {
          background: @mantle;

          .auth-upgrade-cta {
            background: @mantle;
            box-shadow: inset 0 0 0 1px @overlay0;
            color: @yellow;

            &:hover {
              box-shadow: inset 0 0 0 1px @yellow !important;
              color: @yellow !important;
            }
          }
          .auth-logout-cta {
            box-shadow: inset 0 0 0 1px @overlay0;
            background: @mantle;
            color: @text;
          }
        }
      }
    }

    .header {
      &.header--overview, &.header--sub-page {
        color: @text;
      }
      &.header--overview .container, &.header--sub-page .container {
        background: none;
      }

      background: @base;

      .header-info {
        .header-featured-track {
          .featured-item-heading {
            color: @subtext1;
          }
        }

        .header-title-secondary {
          .header-scrobble-since, .header-title-display-name {
            color: @subtext1;
          }
        }

        .header-info-secondary {
          color: @text;
        }
      }
    }
    .header-metadata .header-metadata-title {
      color: @subtext1;
    }
    .secondary-nav {
      .secondary-nav-item-link:hover::after,
      .secondary-nav-item-link--active::after {
        background: @accent;
      }
    }

    .chartlist {
      .chartlist-row {
        &:hover {
          background-color: @surface0;
        }

        &.chartlist-row--highlight, &.chartlist-row--now-scrobbling {
          background-color: fade(@accent, 20%);
        }

        .chartlist-play {
          .chartlist-play-button {
            &::before {
              background-color: transparent;
              filter: @text-filter;
              box-shadow: 0 0 0 1px fade(@mantle, 20%);
            }
          }
        }

        .chartlist-loved {
          button.chartlist-love-button {
            &::before {
              filter: @overlay2-filter;
            }
            &:hover::before, &[data-analytics-action="UnloveTrack"]::before {
              filter: @accent-filter;
            }
          }
        }

        .lazy-buylinks-toggle, .chartlist-more-button {
          &::before {
            filter: @overlay2-filter;
          }
          &:hover::before {
            filter: @subtext0-filter;
          }
        }
        .chartlist-more {
          .chartlist-more-menu {
            .more-item--track::before,
            .more-item--artist::before,
            .more-item--obsession::before {
              filter: @subtext0-filter;
            }
            .more-item--delete::before {
              filter: @red-filter;
            }
          }
        }

        .chartlist-timestamp {
          color: @subtext0;

          .chartlist-now-scrobbling::before {
            filter: @subtext0-filter;
          }
        }

        .chartlist-bar {
          .chartlist-count-bar-slug {
            background-color: transparent !important;
            background-image: linear-gradient(
              to right,
              fade(@accent, 20%),
              fade(@accent, 20%)
            );
            color: @crust;
          }
          .chartlist-count-bar-value {
            color: @text;
          }
        }
      }
      .chartlist-break::after, .chartlist-row::after {
        border-bottom-color: @surface1;
      }

      .cover-art {
        img[src="https://lastfm.freetls.fastly.net/i/u/64s/c6f59c1e5e7240a4c0d427abd71f3dbb.jpg"] {
          mix-blend-mode: screen;
          filter: invert(1);
        }

        &::after {
          box-shadow: inset 0 0 0 1px fade(@subtext0, 7%);
        }
      }
    }
    #top-tracks {
      .section-settings-toggle::before,
      .share-chart .share-button-profile::before {
        filter: @subtext0-filter;
      }
    }

    /* Track Page */
    .catalogue-metadata .lyrics-snippet-more-link a::before,
    .more-link-fullwidth-right a::before,
    .more-items::before,
    .more-link a::before {
      filter: @accent-filter;
    }
    .more-items {
      color: @accent;
    }
    .catalogue-tags {
      .tag a, .tags-add, .tags-add-cta {
        color: @accent;
        box-shadow: inset 0 0 0 1px @accent;

        &:hover {
          color: darken(@accent, 5%) !important;
          box-shadow: inset 0 0 0 1px darken(@accent, 5%) !important;
        }
      }
      .tags-add::before {
        filter: @accent-filter;
      }
    }
    .source-album .source-album-stats,
    .about-artist .about-artist-listeners,
    .trending-tracks .trending-tracks-item-listeners,
    .catalogue-overview-similar-artists-item-aux-text {
      color: @subtext1;
    }

    .trending-tracks-section {
      &, .container {
        color: @text;
        background: @surface0;
      }
    }

    .stationlink-list .stationlink::after,
    .resource-external-link::after,
    .play-this-track-playlink::after {
      border-bottom-color: @surface1;
    }

    .video-preview-upload-cta {
      background: @surface0;
      box-shadow: 0 0 0 2px @surface1;

      &:hover {
        background: @surface1 !important;
      }

      &::before {
        filter: @text-filter;
      }
    }

    /* Shoutbox */
    #shoutbox {
      .shout,
      .shout-form {
        border-bottom-color: @surface0;
      }

      .shout-list {
        .shout-user a {
          color: @text;
        }
        .shout-timestamp {
          color: @subtext0;

          &:focus,
          &:hover {
            color: @text !important;
          }
        }

        .shout-action,
        .shout-reply,
        .vote-button {
          color: @subtext1;

          &::before {
            filter: @subtext1-filter;
          }

          &:focus,
          &:hover {
            color: @text !important;

            &::before {
              filter: @text-filter;
            }
          }
        }

        .vote-button--voted::before,
        .vote-button--unvoted:focus::before,
        .vote-button--unvoted:hover::before {
          filter: @green-filter !important;
        }

        .shout-action-more {
          .shout-more-actions {
            &::before {
              filter: @subtext1-filter;
            }

            &:focus::before,
            &:hover::before {
              filter: @text-filter !important;
            }
          }
          .shout-more-actions-menu {
            .more-item--report::before {
              filter: @subtext0-filter;
            }
          }
        }
      }
    }

    /* Settings */
    .main-content,
    .content-top-has-nav .content-top,
    .two-column-layout .content-top {
      background: @base;
    }
    .two-column-layout .container, .two-column-layout .main-content {
      background-image: none;
    }
    .content-top-has-nav .content-top::after,
    .two-column-layout .content-top::after {
      border-top-color: @surface1;
    }

    .change-username-upsell {
      background-color: fade(@yellow, 20%);
    }

    /* Inbox/Notifications */
    .inbox-notifications {
      .inbox-notifications__item--hover {
        box-shadow: inset 0 -1px @surface1;

        &:hover {
          background-color: @surface0 !important;
        }
      }
      .inbox-notifications__item--highlight-hover {
        background-color: @surface1;
      }
      .inbox-notifications__item-timestamp {
        color: @subtext0;
      }
    }
    .inbox .inbox-buttons .inbox-compose-button {
      .btn-primary();
    }

    /* Home */
    .secondary-nav-item-link {
      &--active::after {
        .homefeed--artists .content-top & {
          background-color: @yellow;
        }
        .homefeed--albums .content-top & {
          background-color: @green;
        }
        .homefeed--tracks .content-top & {
          background-color: @blue;
        }
        .homefeed--events .content-top & {
          background-color: @mauve;
        }
      }
      &:hover::after {
        .homefeed .content-top .secondary-nav-item--artists & {
          background-color: @yellow;
        }
        .homefeed .content-top .secondary-nav-item--albums & {
          background-color: @green;
        }
        .homefeed .content-top .secondary-nav-item--tracks & {
          background-color: @blue;
        }
        .homefeed .content-top .secondary-nav-item--events & {
          background-color: @mauve;
        }
      }
    }
    .recs-feed {
      .recs-feed-item {
        .recs-feed-cover-image-wrap {
          color: @text;
        }

        .recs-feed-playlink::before {
          background-color: @text;
        }

        &.recs-feed-item--artist .context {
          &::before {
            background-color: @yellow;
          }
          &::after {
            mask-position: 0 -32px;
          }
        }
        &.recs-feed-item--track .context {
          &::before {
            background-color: @blue;
          }
          &::after {
            mask-position: 0 -96px;
          }
        }
        &.recs-feed-item--album .context {
          &::before {
            background-color: @green;
          }
          &::after {
            mask-position: 0 -64px;
          }
        }
        .context {
          // Hack using .mask-image() to allow us to mask icons with a background.
          &::before {
            border-radius: 50%;
            content: "";
            height: 32px;
            left: auto;
            position: absolute;
            right: 15px;
            top: -16px;
            width: 32px;
            z-index: 1;
          }
          &::after {
            .mask-image(
              url("/static/images/icons/rec_types_16@2x.5bf9cfd03a3e.png"),
              @crust,
              0 0,
              32px 160px,
              no-repeat,
            );
            z-index: 2;
          }

          color: @subtext1;
          background-color: @surface0;
          box-shadow: inset 1px 0 @surface1, inset -1px -1px @surface1;
        }
      }
    }

    // Events - Browse Popular Music (no event recommendations)
    .no-data-message-button {
      .btn-primary();
    }

    .stationlinks {
      .stationlink-list .stationlink::before {
        background-color: @text;
      }
    }
    .mpu-subscription-upsell {
      color: @subtext0;
    }
    .subscribe-cta {
      background-color: fade(@yellow, 10%);
    }

    .subscribe-cta a, .btn-subscribe {
      background-color: @yellow;
      color: @crust;

      &:hover {
        background-color: darken(@yellow, 5%) !important;
        color: @crust !important;
      }
    }

    /* Profile */
    .profile-cards-items {
      .profile-card .profile-card-content {
        background: linear-gradient(
          90deg,
          @surface0 185px 80%,
          fade(@surface0, 75%) 95%,
          transparent
        );

        .profile-card-content-title {
          color: @text;
        }
        p {
          color: @subtext1;
        }
      }
    }

    /* Reports */
    .listening-report-promo {
      background-color: @surface0 !important;
      border-color: @surface1 !important;

      .listening-report-promo-date::after {
        filter: @overlay2-filter;
      }

      .listening-report-promo-title {
        color: @subtext0;
      }
    }

    /* Library */
    .library-controls {
      .secondary-nav-item .secondary-nav-item-link {
        &::before {
          filter: @text-filter;
        }
        &--active, &:hover {
          color: @accent;

          &::before {
            filter: @accent-filter;
          }
        }
      }
    }
    .library-controls-datepicker {
      .date-range-picker-button {
        color: @accent;

        &::before, .date-range-picker-button-inner::before {
          filter: @accent-filter;
        }
      }
    }
    .date-range-picker-content {
      background-color: @mantle;

      &::before {
        filter: @mantle-filter;
      }

      .date-range-picker-presets a {
        color: @text;

        &:hover {
          background-color: @surface0 !important;
        }
      }

      .date-range-picker-form {
        border-top-color: @surface1;

        .control-label {
          color: @subtext1;
        }
      }
    }
    #scrobble-chart-content {
      .highcharts-background {
        fill: @base !important;
      }
      .highcharts-axis-title {
        fill: @subtext1 !important;
      }
      .highcharts-axis-labels text {
        fill: @subtext0 !important;
      }

      .highcharts-yaxis-grid .highcharts-grid-line {
        stroke: @overlay0 !important;
      }
      .highcharts-xaxis .highcharts-axis-line {
        stroke: @overlay1 !important;
      }

      .highcharts-series-group {
        .highcharts-point {
          fill: fade(@accent, 30%);
        }
      }

      .highcharts-tooltip {
        .highcharts-tooltip-box:not(.highcharts-shadow) {
          fill: @mantle !important;
          stroke: @surface0 !important;
        }

        text {
          fill: @text !important;
        }
      }
    }
    .metadata-title {
      color: @subtext1;
    }
    .date-heading {
      color: @subtext0;
    }

    // Pagination
    .pagination {
      .pagination-page {
        &[aria-current] {
          color: @accent;
          box-shadow: inset 0 -2px @accent;
        }
        &:not(.pagination-page--ellipsis):hover {
          box-shadow: inset 0 -2px @accent;
        }
      }
    }

    /* Followers */
    .text-light {
      color: @subtext1;
    }
    .user-list-follower-btn {
      [data-toggle-button-current-state="followed"] & {
        background-color: @green;

        &:hover {
          background-color: @red !important;
        }
      }
      [data-toggle-button-current-state="unfollowed"] & {
        background-color: @accent;

        &:hover {
          background-color: darken(@accent, 5%) !important;
        }
      }

      &::before {
        filter: @crust-filter;
      }
    }

    /* Obsessions */
    .obsession-candidates-row::before {
      border-top-color: @surface1;
    }

    // TODO: https://www.last.fm/music
    // TODO: https://www.last.fm/user/*/listening-report/week (Reports)
  }
}

// Usage:
// .maskimage(mask-image, background-color, mask-position, mask-size, mask-repeat);
// Setting any value to "skip" skips that attribute.
// We cannot apply filters to psuedo elements with background-images when the pseudo element also has a background(-color), which is when this must be used.
.mask-image(
  @mask-image: url(""),
  @mask-color: skip,
  @mask-position: skip,
  @mask-size: skip,
  @mask-repeat: skip,
) {
  & when not(@mask-color = skip) {
    background-image: none !important;
    background-color: @mask-color;
  }
  & when not(@mask-image = skip) {
    mask-image: @mask-image;
  }
  & when not(@mask-position = skip) {
    mask-position: @mask-position;
  }
  & when not(@mask-size = skip) {
    mask-size: @mask-size;
  }
  & when not(@mask-repeat = skip) {
    mask-repeat: @mask-repeat;
  }
}

